#include <stdio.h>
#include <string.h>
#define MAX 10000
int mul[10][10];
int main() {
    for (int i = 1; i <= 9; i++) {
        for (int j = 1; j <= 9; j++) {
            scanf("%d", &mul[i][j]);
        }
    }
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[MAX];
        scanf("%s", A);
        int len = strlen(A);
        int Mod;
        scanf("%d", &Mod);
        long long sum = 0;
        for (int i = 1; i <= atoi(A); i++) {
            for (int j = 1; j <= atoi(A); j++) {
                long long product = 0;
                int carry = 0;
                for (int k = 0; k < len; k++) {
                    int digit1 = i % 10;
                    int digit2 = j % 10;
                    product += (mul[digit1][digit2] + carry) * (long long)pow(10, k);
                    carry = (mul[digit1][digit2] + carry) / 10;
                    i /= 10;
                    j /= 10;
                }
                sum += product;
            }
        }
        printf("%lld\n", sum % Mod);
    }
    return 0;
}

