import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int[][] mul = new int[10][10];
        for (int i = 1; i <= 9; i++) {
            for (int j = 1; j <= 9; j++) {
                mul[i][j] = sc.nextInt();
            }
        }
        int T = sc.nextInt();
        while (T-- > 0) {
            String A = sc.next();
            int len = A.length();
            int Mod = sc.nextInt();
            long sum = 0;
            for (int i = 1; i <= Integer.parseInt(A); i++) {
                for (int j = 1; j <= Integer.parseInt(A); j++) {
                    long product = 0;
                    int carry = 0;
                    for (int k = 0; k < len; k++) {
                        int digit1 = i % 10;
                        int digit2 = j % 10;
                        product += (mul[digit1][digit2] + carry) * (long) Math.pow(10, k);
                        carry = (mul[digit1][digit2] + carry) / 10;
                        i /= 10;
                        j /= 10;
                    }
                    sum += product;
                }
            }
            System.out.println(sum % Mod);
        }
    }
}

